function createOverlayDivElementsInRange(range,overlayClassName,skipAnimatedNode){const added=[];const commonAncestor=range.commonAncestorContainer;const processNode=node=>{const parent=node.parentElement;if(!parent||parent.closest("script, style, img, video, audio")){return}if(skipAnimatedNode&&isNodeAnimated(node)){return}const nodeRange=document.createRange();nodeRange.selectNodeContents(node);if(node===range.startContainer){nodeRange.setStart(node,range.startOffset)}if(node===range.endContainer){nodeRange.setEnd(node,range.endOffset)}const selectedText=nodeRange.toString();if(!selectedText.trim()){return}const{rects,position}=getRangePositionAndRects(nodeRange);rects.forEach(rect=>{added.push(createOverlayDivElementInRect(rect,position,overlayClassName))})};if(commonAncestor.nodeType===Node.TEXT_NODE){processNode(commonAncestor)}else{const walker=document.createTreeWalker(commonAncestor,NodeFilter.SHOW_TEXT,{acceptNode:node=>{return range.intersectsNode(node)?NodeFilter.FILTER_ACCEPT:NodeFilter.FILTER_REJECT}});let currentNode;while(currentNode=walker.nextNode()){processNode(currentNode)}}return added}function createOverlayDivElementInRect(rect,position,overlayClassName){const element=document.createElement("div");element.className=overlayClassName;Object.assign(element.style,{position:`${position}`,top:`${rect.top}px`,left:`${rect.left}px`,width:`${rect.width}px`,height:`${rect.height}px`,boxSizing:"border-box",pointerEvents:"none",WebkitUserSelect:"none",userSelect:"none"});return element}function removeOverlayDiv(overlayClassName){const elements=document.querySelectorAll(`div.${overlayClassName}`);elements.forEach(element=>{element.remove()})}function getRangePositionAndRects(range){const clientRects=range.getClientRects();if(clientRects.length===0){return{position:"absolute",rects:[]}}const scrollX=document.scrollingElement.scrollLeft;const scrollY=document.scrollingElement.scrollTop;const isFixed=isNodeInFixedContext(range.commonAncestorContainer);const scrollWidth=document.scrollingElement.scrollWidth;const scrollHeight=document.scrollingElement.scrollHeight;const adjustedRects=[];for(const rect of clientRects){if(rect.width===0||rect.height===0){continue}if(isFixed){adjustedRects.push({top:rect.top,left:rect.left,bottom:rect.bottom,right:rect.right,width:rect.width,height:rect.height})}else{let top=rect.top+scrollY;let left=rect.left+scrollX;let bottom=rect.bottom+scrollY;let right=rect.right+scrollX;top=Math.max(0,Math.min(top,scrollHeight));left=Math.max(0,Math.min(left,scrollWidth));bottom=Math.max(0,Math.min(bottom,scrollHeight));right=Math.max(0,Math.min(right,scrollWidth));const width=right-left;const height=bottom-top;if(width<=0||height<=0){continue}adjustedRects.push({top:top,left:left,bottom:bottom,right:right,width:width,height:height})}}return{position:isFixed?"fixed":"absolute",rects:adjustedRects}}function isNodeInFixedContext(node){let element=node.nodeType===Node.TEXT_NODE?node.parentElement:node;while(element&&element!==document.documentElement){const style=window.getComputedStyle(element);if(style.position==="fixed"){let ancestor=element.parentElement;let nextElement=element.parentElement;while(ancestor&&ancestor!==document.documentElement){const ancestorStyle=window.getComputedStyle(ancestor);if(createsContainingBlock(ancestorStyle)){break}if(ancestorStyle.position==="fixed"){nextElement=ancestor;break}ancestor=ancestor.parentElement}if(!ancestor||ancestor===document.documentElement){return true}element=nextElement;continue}element=element.parentElement}return false}function createsContainingBlock(style){const isActive=val=>val&&val!=="none";if(isActive(style.transform)||isActive(style.perspective)||isActive(style.filter)){return true}const backdrop=style.backdropFilter||style.webkitBackdropFilter;if(isActive(backdrop)){return true}const willChange=style.willChange;if(willChange&&/transform|perspective|filter/.test(willChange)){return true}const contain=style.contain;if(contain&&/paint|layout|strict|content/.test(contain)){return true}if(style.containerType&&style.containerType!=="normal"){return true}return false}function isNodeAnimated(node,skipRunningCheck=false){let currentElement=node.nodeType===Node.TEXT_NODE?node.parentElement:node;while(currentElement&&currentElement!==document.body){const animations=currentElement.getAnimations();const relevantCssAnimations=animations.filter(anim=>{const isCssAnim=anim instanceof CSSAnimation;if(skipRunningCheck){return isCssAnim}return anim.playState==="running"&&isCssAnim});if(relevantCssAnimations.length>0){return true}currentElement=currentElement.parentElement}return false}